-----------------------------------------------------------------
---攻击行为
-----------------------------------------------------------------
---@type LFightIdleBaseAction
local LFightIdleBaseAction = LXImport(".LFightIdleBaseAction")

---@class LFightIdleAtkAction:LFightIdleBaseAction
local LFightIdleAtkAction = LxClass("LFightIdleAtkAction",LFightIdleBaseAction)
-----------------------------------------------------------------
LFightIdleAtkAction.PHASE_WAIT = 0 --0等待下一次检测
LFightIdleAtkAction.PHASE_ATK = 1 --1--攻击中
LFightIdleAtkAction.PHASE_CLOSETAR = 2 --2--同地板寻怪中
LFightIdleAtkAction.PHASE_PATH = 3 --3--跳地板中寻怪

function LFightIdleAtkAction:LFightIdleAtkAction()
	self._action = LFightIdleConst.ACTION_ATK

	self._waitInterval = 0.1

	self._phase = LFightIdleAtkAction.PHASE_WAIT --0 等待下一次检测，1 --攻击中，2-- 同地板寻怪中, 3--跳地板中寻怪

	self._waitNextCheckTime = 0
end

-----------------------------------------------------------------
function LFightIdleAtkAction:OnRun(time)
	if self._phase == LFightIdleAtkAction.PHASE_WAIT  then
		if(self._waitNextCheckTime <= time) then
			self:OnCheck()
		end
		return
	end

	if self._phase == LFightIdleAtkAction.PHASE_ATK then
		local actor = self._obj:GetAtkActor()
		if actor:IsAttacking() then
			return
		end
		self:TryAtk()
		return
	end

	if self._phase == LFightIdleAtkAction.PHASE_CLOSETAR then
		local actor = self._obj:GetMoveActor()
		if(actor:IsMoving()) then return end
		self:TryAtk()
		return
	end

	if self._phase == LFightIdleAtkAction.PHASE_PATH then
		local actor = self._obj:GetPathActor()
		if(actor:IsPathing()) then return end
		self:ResetWaitPhase()
	end

end
-----------------------------------------------------------------
--转换成等待
function LFightIdleAtkAction:ResetWaitPhase()
	self._phase = LFightIdleAtkAction.PHASE_WAIT
	if self._obj:SetStatus(LFightIdleConst.STATUS_IDLE) then
		self._obj:PlayIdleAni()
	end
end

--尝试攻击
function LFightIdleAtkAction:TryAtk()
	if not self:CheckAITargetValid() then
		self:ResetWaitPhase()
		return
	end
	if not self:CheckCanAttackTar() then
		self:CloseToTar()
		return
	end
	self:GotoAtk()
end
-----------------------------------------------------------------
function LFightIdleAtkAction:StartAction()
	self._waitNextCheckTime = 0
	self._phase = LFightIdleAtkAction.PHASE_WAIT
end

-----------------------------------------------------------------
--检测应该做什么 靠近目标，攻击目标，跳地板 还是切换会巡逻状态
function LFightIdleAtkAction:OnCheck()
	self._waitNextCheckTime = self:GetTime() + self._waitInterval
	--目标还存在 开始攻击
	if self:CheckAITargetValid() then
		if self:CheckCanAttackTar() then
			self:GotoAtk()
		else
			self:CloseToTar()
		end
		return
	end

	self._phase = LFightIdleAtkAction.PHASE_WAIT

	local bOnlyCheckSameBorad = self._obj:IsCheckSameBoard()

	local resultObj = nil
	if bOnlyCheckSameBorad then
		local isHaveSameBoard,tarObj = self:CheckSameBoardTarget()
		--怪物没有目标就继续巡逻
		if not isHaveSameBoard or not tarObj then
			--转为巡逻
			local ai = self._ai
			ai:ChangeAction(LFightIdleConst.ACTION_PATROL)
			return
		end
		resultObj = tarObj
	else
		local objCtrl = self:GetObjCtrl()
		local teamList = objCtrl:GetOppositeTeamBySide(self._obj:GetSide())
		local tarObj = self:SelNearestTarget(teamList)
		if not tarObj then
			--所有地板都没有活着的怪了,转成扫描
			local ai = self._ai
			ai:ChangeAction(ai:GetDefaultAction())
			return
		end
		resultObj = tarObj
	end

	local tarBoardRefId = resultObj:GetBoardRefId()
	local objBoardRefId = self._obj:GetBoardRefId()

	self._obj:SetTarObjKey(resultObj:GetObjectKey())

	if tarBoardRefId == objBoardRefId then
		--同地板
		if self:CheckCanAttackTar() then
			self:GotoAtk()
		else
			self:CloseToTar()
		end
	else
		--跳地板
		local toBoardRefId = resultObj:GetBoardRefId()
		self:GotoOtherBoard(toBoardRefId,resultObj:GetPosition())
	end
end

--检测同地板有没有合适的目标,怪物选择目标
function LFightIdleAtkAction:CheckSameBoardTarget()
	local objCtrl = self:GetObjCtrl()
	local teamList = objCtrl:GetOppositeTeamBySide(self._obj:GetSide())

	local boardRefId = self._obj:GetBoardRefId()

	local sameBoardObjList = {}
	local diffBoardObjList = {}

	for k,v in ipairs(teamList) do
		if v:IsLive() then
			if v:GetBoardRefId() == boardRefId then
				table.insert(sameBoardObjList,v)
			else
				table.insert(diffBoardObjList,v)
			end
		end
	end

	if #sameBoardObjList > 0 then
		return true,self:SelSameBoardOneTarget(sameBoardObjList)
	end

	--if bOnlyCheckSameBoard then return false end
	--
	--if #diffBoardObjList > 0 then
	--	return false,self:SelOneOtherBoard(diffBoardObjList)
	--end

	return false
end

--查找地板上 没有英雄的一个地块，路径最短的
--都有有英雄，则选路径最短的
function LFightIdleAtkAction:SelOneOtherBoard(tarList)
	local objCtrl = self:GetObjCtrl()
	local pathCtrl = self:GetPathCtrl()
	local teamList = objCtrl:GetTeamBySide(self._obj:GetSide())

	local dicHeroBoardLocation = {}
	for k,v in ipairs(teamList) do
		local vBoardRefId = v:GetTargetBoardRefId()
		if not vBoardRefId then
			vBoardRefId = v:GetBoardRefId()
		end

		dicHeroBoardLocation[vBoardRefId] = true
	end

	local boardRefId = self._obj:GetBoardRefId()
	local dicBoardTar = {}
	local idleBoardList = {}
	local heroBoardList = {}
	for k,v in ipairs(tarList) do
		if v:IsLive() then
			local vBoard = v:GetBoardRefId()
			local tmpList = dicBoardTar[vBoard]
			if not tmpList then
				tmpList = {}
				if not dicHeroBoardLocation[vBoard] then
					table.insert(idleBoardList,vBoard)
				else
					table.insert(heroBoardList,vBoard)
				end
				dicBoardTar[vBoard] = tmpList
			end
			table.insert(tmpList,v)
		end
	end

	local pathList = {}
	if #idleBoardList > 0 then
		for k,v in ipairs(idleBoardList) do
			local bHave,links = pathCtrl:FindPath(boardRefId,v)
			if bHave then
				table.insert(pathList,{data=v,len=#links})
			end
		end
	elseif #heroBoardList > 0 then
		for k,v in ipairs(heroBoardList) do
			local bHave,links = pathCtrl:FindPath(boardRefId,v)
			if bHave then
				table.insert(pathList,{data=v,len=#links})
			end
		end
	end

	local pathLen = #pathList
	if pathLen > 0 then
		--随机一个路径最短的
		table.sort(pathList,function (sA,sB)
			return sA.len < sB.len
		end)
		local minList = {}
		local minLen = pathList[1].len

		for k,v in ipairs(pathList) do
			if v.len ~= minLen then
				break
			end
			table.insert(minList,v.data)
		end
		local board = minList[LFightIdleConst.RandInteger(#minList)]
		local tempList = dicBoardTar[board]
		return tempList[1]
	end
end

--选择一个单位，优先选择能马上打到的
--都不能攻击的时候，选择最近的一个
function LFightIdleAtkAction:SelSameBoardOneTarget(tarList)
	--找一个可以攻击到的单位
	local canAtkList = {}
	local moveAtkList = {}
	local objPos = self._obj:GetPosition()
	local nowX = objPos.x
	local atkDis = self._obj:GetAtkDis()

	for k,v in ipairs(tarList) do
		if v:IsReady() then
			local tarPos = v:GetPosition()
			local tarBodyX = v:GetBodyX()
			local distance = Mathf.Abs(tarPos.x - nowX)
			local realAtkDis = tarBodyX + atkDis
			if LFightIdleConst.Approximately(distance,realAtkDis) or distance < realAtkDis then
				table.insert(canAtkList,v)
			else
				table.insert(moveAtkList,{dis=distance,data=v})
			end
		end
	end

	--不需要移动就能打到的单位
	if #canAtkList > 0 then
		local randIndex = LFightIdleConst.RandInteger(#canAtkList)
		return canAtkList[randIndex]
	end

	--需要走一下才能打到的单位
	if #moveAtkList > 0 then
		table.sort(moveAtkList,function (v1,v2)
			return v1.dis < v2.dis
		end)
		return moveAtkList[1].data
	end
end

--选择绝对距离最近的一个
function LFightIdleAtkAction:SelNearestTarget(tarList)
	--找一个可以攻击到的单位
	local sameBoardCanAtkList = {}
	local moveAtkList = {}
	local objPos = self._obj:GetPosition()
	local nowX = objPos.x
	local atkDis = self._obj:GetAtkDis()

	local boardRefId = self._obj:GetBoardRefId()

	local bHaveAtk = false
	objPos = objPos:Clone()
	objPos.z = 0
	for k,v in ipairs(tarList) do
		if v:IsLive() then
			local tarPos = v:GetPosition()
			if v:GetBoardRefId() == boardRefId then
				local tarBodyX = v:GetBodyX()
				local distance = Mathf.Abs(tarPos.x - nowX)
				local realAtkDis = tarBodyX + atkDis
				if LFightIdleConst.Approximately(distance,realAtkDis) or distance < realAtkDis then
					table.insert(sameBoardCanAtkList,v)
					bHaveAtk = true
				end
			end
			if not bHaveAtk then
				tarPos = tarPos:Clone()
				tarPos.z = 0
				local dis = (tarPos - objPos):SqrMagnitude()
				table.insert(moveAtkList,{dis=dis,data=v})
			end
		end
	end

	--不需要移动就能打到的单位
	if #sameBoardCanAtkList > 0 then
		local randIndex = LFightIdleConst.RandInteger(#sameBoardCanAtkList)
		return sameBoardCanAtkList[randIndex]
	end

	--需要走一下才能打到的单位
	if #moveAtkList > 0 then
		table.sort(moveAtkList,function (v1,v2)
			return v1.dis < v2.dis
		end)
		--for k,v in ipairs(moveAtkList) do
		--	print("dis = "..v.dis.." name = "..v.data:GetObjectKey().." "..v.data:GetObjName())
		--end
		return moveAtkList[1].data
	end
	return nil
end

----------------------------------------------------------------
--检测目标有效性质
function LFightIdleAtkAction:CheckAITargetValid()
	local tarObjKey = self._obj:GetTarObjKey()

	if not tarObjKey then return false end

	local objCtrl =self:GetObjCtrl()

	local tarObj = objCtrl:GetObjByKey(tarObjKey)

	if not tarObj or not tarObj:IsLive() then
		return false
	end

	if tarObj:GetBoardRefId() ~= self._obj:GetBoardRefId() then
		return false
	end

	return true
end

--检测目标是否在攻击距离内
--只能站在边缘，检测是不是站在了边缘
function LFightIdleAtkAction:CheckCanAttackTar()
	local obj = self._obj
	--local locationType = obj:GetLocationType()
	--if locationType == LFightIdleConst.LOCATION_EDGE then
	--	local nowMinPos,nowMaxPos = obj:GetPathData()
	--	local curPos = obj:GetPosition()
	--	if LFightIdleConst.Approximately(curPos.x, nowMaxPos.x) or LFightIdleConst.Approximately(curPos.x, nowMinPos.x) then
	--		return true
	--	end
	--	return false
	--else
	local tarObjKey = obj:GetTarObjKey()

	local objCtrl =self:GetObjCtrl()
	local tarObj = objCtrl:GetObjByKey(tarObjKey)
	local tarPos = tarObj:GetPosition()
	local curPos = obj:GetPosition()

	local tarBoardRefId = tarObj:GetBoardRefId()
	local objBoardRefId = obj:GetBoardRefId()
	if tarBoardRefId ~= objBoardRefId then
		return false
	end

	local atkDis = obj:GetAtkDis() + tarObj:GetBodyX()
	local dis = Mathf.Abs(tarPos.x - curPos.x)
	if LFightIdleConst.Approximately(dis, atkDis) or dis < atkDis then
		return true
	end
	return false
	--end
end

-----------------------------------------------------------------
--靠近目标
function LFightIdleAtkAction:CloseToTar()
	self._phase = LFightIdleAtkAction.PHASE_CLOSETAR
	local obj = self._obj
	local tarPos
	local curPos = obj:GetPosition()
	--local locationType = obj:GetLocationType()

	local atkDistance = obj:GetAtkDis()
	local tarBodyX = 0

	----站在边缘的移动到最近的边缘
	--if locationType == LFightIdleConst.LOCATION_EDGE then
	--	atkDistance = 0
	--	local nowMinPos,nowMaxPos = obj:GetPathData()
	--	local minEdgeDis = Mathf.Abs(nowMinPos.x - curPos.x)
	--	local maxEdgeDis = Mathf.Abs(nowMaxPos.x - curPos.x)
	--	if LFightIdleConst.Approximately(minEdgeDis,maxEdgeDis) then
	--		if LFightIdleConst.RandInteger(2) > 1 then
	--			tarPos = nowMinPos
	--		else
	--			tarPos = nowMaxPos
	--		end
	--	elseif minEdgeDis < maxEdgeDis then
	--		tarPos = nowMinPos
	--	else
	--		tarPos = nowMaxPos
	--	end
	--
	--else
		local tarObjKey = obj:GetTarObjKey()
		local objCtrl = self:GetObjCtrl()
		local tarObj = objCtrl:GetObjByKey(tarObjKey)
		tarPos = tarObj:GetPosition()
	tarBodyX = tarObj:GetBodyX()
	--end
	atkDistance = tarBodyX + atkDistance


	local moveX = tarPos.x
	local moveDis = moveX - curPos.x

	local dir = 0
	if moveDis < 0 then --目标在左边
		moveX = moveX + atkDistance - 0.05
		dir = LFightIdleConst.DIRECTION_LEFT
	else--目标在右边
		dir = LFightIdleConst.DIRECTION_RIGHT
		moveX = moveX - atkDistance + 0.05
	end

	local speed = obj:GetMoveSpeed()
	local time = Mathf.Abs(moveX - curPos.x) / speed * 100

	if obj:SetStatus(LFightIdleConst.STATUS_MOVE) or not obj:IsRunAni() then
		obj:PlayRunAni()
	end
	local tarPos = Vector3(moveX,curPos.y,curPos.z)

	obj:ChangeDirToPos(tarPos)

	obj:GetMoveActor():MoveTo(tarPos,time)
end

--攻击
function LFightIdleAtkAction:GotoAtk()
	self._phase = LFightIdleAtkAction.PHASE_ATK
	self._obj:GetAtkActor():DoAtk()
end
-----------------------------------------------------------------
--跳到其他地板
function LFightIdleAtkAction:GotoOtherBoard(toBoardRefId,toPos)
	self._phase = LFightIdleAtkAction.PHASE_PATH
	self._obj:SetStatus(LFightIdleConst.STATUS_PATH)
	self._obj:GetPathActor():StartPathing(toBoardRefId,toPos)
end

-----------------------------------------------------------------
function LFightIdleAtkAction:StopAction()

end

function LFightIdleAtkAction:Destroy()

	LFightIdleBaseAction.Destroy(self)
end


return LFightIdleAtkAction